// agentVersionRow is one agent's version compared against the fleet newest.
type agentVersionRow struct {
	AgentName string `json:"agentName"`
	Serial    string `json:"serial"`
	Client    string `json:"client"`
	Version   string `json:"version"`
	Newest    string `json:"newest"`
	Outdated  bool   `json:"outdated"`
}

// pp:data-source local
func newNovelAgentVersionsCmd(flags *rootFlags) *cobra.Command {
	var flagOutdated bool
	var dbPath string

	cmd := &cobra.Command{
		Use:   "agent-versions",
		Short: "Audit agent software versions across the entire fleet and flag every machine running an outdated agent",
		Example: strings.Trim(`
  # Every machine lagging behind the fleet's newest agent version
  datto-bcdr-cli agent-versions --outdated --json`, "\n"),
		Annotations: map[string]string{"mcp:read-only": "true"},
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}
			if err := validateDataSourceStrategy(flags, "local"); err != nil {
				return err
			}
			if dbPath == "" {
				dbPath = defaultDBPath("datto-bcdr-cli")
			}
			db, err := nvOpenStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening database: %w", err)
			}
			defer db.Close()

			if !hintIfUnsynced(cmd, db, "agent") {
				hintIfStale(cmd, db, "agent", flags.maxAge)
			}

			rows, err := db.DB().QueryContext(cmd.Context(), `
				SELECT
					COALESCE(json_extract(data,'$.agentName'), ''),
					COALESCE(json_extract(data,'$.deviceSerialNumber'), ''),
					COALESCE(json_extract(data,'$.clientCompanyName'), ''),
					COALESCE(json_extract(data,'$.agentVersion'), '')
				FROM "agent"`)
			if err != nil {
				return fmt.Errorf("querying agents: %w", err)
			}
			defer rows.Close()

			type rawAgent struct {
				name, serial, client, version string
			}
			var loaded []rawAgent
			var versions []string
			for rows.Next() {
				var a rawAgent
				if err := rows.Scan(&a.name, &a.serial, &a.client, &a.version); err != nil {
					return fmt.Errorf("scanning agent: %w", err)
				}
				loaded = append(loaded, a)
				versions = append(versions, a.version)
			}
			if err := rows.Err(); err != nil {
				return fmt.Errorf("iterating agents: %w", err)
			}

			newest := newestVersion(versions)

			results := make([]agentVersionRow, 0, len(loaded))
			for _, a := range loaded {
				outdated := a.version != newest
				if flagOutdated && !outdated {
					continue
				}
				results = append(results, agentVersionRow{
					AgentName: a.name,
					Serial:    a.serial,
					Client:    a.client,
					Version:   a.version,
					Newest:    newest,
					Outdated:  outdated,
				})
			}

			// ORDER BY agentName.
			sort.SliceStable(results, func(i, j int) bool {
				return results[i].AgentName < results[j].AgentName
			})

			return flags.printJSON(cmd, results)
		},
	}
	cmd.Flags().BoolVar(&flagOutdated, "outdated", false, "Only show agents not running the newest fleet version")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path (defaults to standard location)")
	return cmd
}

// compareVersions compares two dotted version strings by numeric segment.
// Returns -1 if a < b, 0 if equal, +1 if a > b. Each segment is parsed as an
// integer; a non-numeric tail within a segment is ignored (e.g. "1.2-beta"
// segment "2-beta" reads as 2). Missing segments count as 0, so "2.0" > "1.99"
// and "1.10.0" > "1.9.9".
func compareVersions(a, b string) int {
	as := strings.Split(a, ".")
	bs := strings.Split(b, ".")
	n := len(as)
	if len(bs) > n {
		n = len(bs)
	}
	for i := 0; i < n; i++ {
		var av, bv int
		if i < len(as) {
			av = leadingInt(as[i])
		}
		if i < len(bs) {
			bv = leadingInt(bs[i])
		}
		if av != bv {
			if av < bv {
				return -1
			}
			return 1
		}
	}
	return 0
}

// leadingInt parses the leading integer of a version segment, ignoring any
// non-numeric tail. "10" -> 10, "2beta" -> 2, "beta" -> 0, "" -> 0.
func leadingInt(seg string) int {
	end := 0
	for end < len(seg) && seg[end] >= '0' && seg[end] <= '9' {
		end++
	}
	if end == 0 {
		return 0
	}
	n, err := strconv.Atoi(seg[:end])
	if err != nil {
		return 0
	}
	return n
}

// newestVersion returns the highest version among the inputs by
// compareVersions ordering. Empty strings are skipped. Returns "" when no
// non-empty version is present.
func newestVersion(versions []string) string {
	newest := ""
	for _, v := range versions {
		if v == "" {
			continue
		}
		if newest == "" || compareVersions(v, newest) > 0 {
			newest = v
		}
	}
	return newest
}
